            {
                heading: 'Nilai-Nilai Kami',
                content: 'Integritas, Inovasi, Kolaborasi, dan Komitmen terhadap kepuasan pengguna adalah nilai-nilai inti yang kami pegang teguh dalam setiap layanan yang kami berikan.'
            }
        ]
    },
    'kebijakan-privasi': {
        title: 'Kebijakan Privasi',
        icon: '🔒',
        sections: [
            {
                heading: 'Informasi yang Kami Kumpulkan',
                content: 'Kami mengumpulkan informasi pribadi seperti nama, alamat email, nomor telepon, dan data profesional lainnya yang Anda berikan saat mendaftar atau menggunakan layanan kami.'
